// Form/Form.tsx

import React, {useEffect, useImperativeHandle, useMemo, useState} from 'react';
import {
    type DeepPartial,
    type FieldValues,
    FormProvider,
    type UseFormReset,
    type UseFormSetValue
} from 'react-hook-form';
import {useFormManager} from './hooks';
import type {IFormComponent, IUseFormReturn, SetManyOpts} from "@lmb-it/kitsconcerto-types";
import {SubmitButton} from "./components/SubmitButton";
import {FormRenderer} from "./components/FormRenderer";
import {Flex} from "../_compat";

const Form = <T extends FieldValues>({
                                         elements,
                                         onSubmit,
                                         onInvalidSubmit,
                                         outputFormat = 'Json',
                                         id = "go-markets-form",
                                         grid, onChangeSingleValue,
                                         onChange,
                                         submitButtonProps,
                                         onMount,
                                         ref,
                                         children,
                                         animation,
                                         style
                                     }: IFormComponent<T>) => {

    const [isSubmitting, setIsSubmitting] = useState(false);

    // Destructure the new, corrected return shape from the hook
    const {formMethods, handleSubmit} = useFormManager({
        elements,
        onSubmit,
        onInvalidSubmit,
        outputFormat,
        onChangeSingleValue,
        onChange, id
    }, isSubmitting, setIsSubmitting);

    const [focusedField, setFocusedField] = useState<string>('');
    // Destructure the specific methods we need for the renderer from the original formMethods
    const {getValues, control, formState} = formMethods;

    useEffect(() => {
        onMount && onMount(formMethods)
    }, []);

    /** Factory. Feed setValue/reset from your useFormManager. */
    function createFormAppliers<T extends FieldValues>(deps: {
        setValue: UseFormSetValue<T>;
        reset?: UseFormReset<T>;
        getValues?: () => T;
    }) {
        const {setValue, reset, getValues} = deps;

        /** Patch many fields (deep paths supported). */
        const setValues = (patch: DeepPartial<T>, opts: SetManyOpts = {shouldDirty: true}) => {
            const walk = (base: string, v: unknown) => {
                if (v !== null && typeof v === "object" && !Array.isArray(v)) {
                    for (const [k, vv] of Object.entries(v as Record<string, unknown>)) {
                        walk(base ? `${base}.${k}` : k, vv);
                    }
                } else {
                    setValue(base as any, v as any, opts);
                }
            };
            walk("", patch as any);
        };

        /** Merge patch into current values using reset (fast for large updates). */
        const mergeReset = (patch: DeepPartial<T>) => {
            if (!reset || !getValues) return;
            const cur = getValues();
            const deepMerge = (a: any, b: any): any => {
                const out: any = Array.isArray(a) ? [...a] : {...a};
                for (const k of Object.keys(b ?? {})) {
                    const bv = (b as any)[k];
                    out[k] =
                        bv && typeof bv === "object" && !Array.isArray(bv)
                            ? deepMerge(out[k] ?? {}, bv)
                            : bv;
                }
                return out;
            };
            reset(deepMerge(cur, patch), {
                keepErrors: true,
                keepDirty: true,
                keepTouched: true,
                keepSubmitCount: true,
            });
        };

        return {setValues, mergeReset};
    }

    const IRefReturn: IUseFormReturn<T> = useMemo(() => {
        return {
            id,
            setIsSubmitting,
            ...formMethods,
            ...createFormAppliers({
                setValue: formMethods.setValue,
                reset: formMethods.reset,
                getValues: formMethods.getValues,
            }),
            onFormSubmit: handleSubmit,
        }
    }, [handleSubmit, formMethods, setIsSubmitting, id])
    useImperativeHandle(ref, () => {
        return IRefReturn;
    }, [formState]);



    return (
        // Pass ONLY the original, unmodified formMethods to the provider. This fixes the error.
        <FormProvider {...formMethods}>
            <Flex
                id={id}
                w={"full"}
                gap={10}
                flexDirection={"column"}
                position={'relative'}
                entering={animation?.entering}
                exiting={animation?.exiting}
                animationDuration={animation?.animationDuration}
                animationDelay={animation?.animationDelay}
                {...(style || {})}>


                <FormRenderer
                    elements={elements}
                    control={control}
                    grid={grid}
                    getValues={getValues}
                    focusedField={focusedField}
                    setFocusedField={setFocusedField}
                />

                {typeof children === "function"
                    ? children(IRefReturn)
                    : children}

                {submitButtonProps != "none" && (
                    <Flex justifyContent="flex-end" w="full">
                        <SubmitButton
                            submitButtonProps={submitButtonProps}
                            formMethods={formMethods}
                            isSubmitting={isSubmitting}
                            handleSubmit={handleSubmit}
                        />
                    </Flex>
                )}
            </Flex>
        </FormProvider>
    );
};

export default Form;
